n class=&#34;token number&#34;&gt;127.0&lt;/span&gt;.0.1/8 scope &lt;span class=&#34;token function&#34;&gt;host&lt;/span&gt; lo&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       valid_lft forever preferred_lft forever&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;: eth0@if7: &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;BROADCAST,MULTICAST,UP,LOWER_UP&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; mtu &lt;span class=&#34;token number&#34;&gt;1500&lt;/span&gt; qdisc noqueue state UP group default &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    link/ether 02:42:ac:11:00:02 brd ff:ff:ff:ff:ff:ff link-netnsid &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    inet &lt;span class=&#34;token number&#34;&gt;172.17&lt;/span&gt;.0.2/16 brd &lt;span class=&#34;token number&#34;&gt;172.17&lt;/span&gt;.255.255 scope global eth0&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       valid_lft forever preferred_lft forever&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;font-colorcornflowerblue86docker-host网络模式font&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#font-colorcornflowerblue86docker-host网络模式font&#34;&gt;#&lt;/a&gt; &lt;font color=&#39;cornflowerblue&#39;&gt;8.6docker host 网络模式&lt;/font&gt;&lt;/h2&gt;
